13	export async function generateMetadata({ params }: { params: Promise<{ slug: string }> }): Promise<Metadata> {
14	  const { slug } = await params;
15	  const row = pickConclusion(slug);
16	  if (!row) return { title: "Not found" };
17	  return { title: row.payload.conclusionText.slice(0, 80) };
18	}
