20	export default async function LatestConclusionPage({ params }: { params: Promise<{ slug: string }> }) {
21	  const { slug } = await params;
22	  const row = pickConclusion(slug);
23	  if (!row) notFound();
24	
25	  const allVersions = bundle.conclusions.filter((c) => c.slug === row.slug).sort((a, b) => a.version - b.version);
26	  const responses = responsesForPublishedId(row.id);
27	
28	  return <ConclusionView row={row} allVersions={allVersions} responses={responses} />;
29	}
