1	import type { Metadata } from "next";
2	import { notFound } from "next/navigation";
3	
4	import { bundle, pickConclusion, responsesForPublishedId } from "@/lib/bundle";
5	
6	import ConclusionView from "@/components/ConclusionView";
7	
8	export async function generateStaticParams() {
9	  return bundle.conclusions.map((c) => ({ slug: c.slug, version: String(c.version) }));
10	}
11	
12	export async function generateMetadata({
13	  params,
14	}: {
15	  params: Promise<{ slug: string; version: string }>;
16	}): Promise<Metadata> {
17	  const { slug, version } = await params;
18	  const v = Number(version);
19	  const row = pickConclusion(slug, Number.isFinite(v) ? v : undefined);
20	  if (!row) return { title: "Not found" };
21	  return { title: `${row.payload.conclusionText.slice(0, 72)} (v${row.version})` };
22	}
23	
24	export default async function VersionedConclusionPage({
25	  params,
26	}: {
27	  params: Promise<{ slug: string; version: string }>;
28	}) {
29	  const { slug, version } = await params;
30	  const v = Number(version);
31	  if (!Number.isFinite(v)) notFound();
32	
33	  const row = pickConclusion(slug, v);
34	  if (!row) notFound();
35	
36	  const allVersions = bundle.conclusions.filter((c) => c.slug === row.slug).sort((a, b) => a.version - b.version);
37	  const responses = responsesForPublishedId(row.id);
38	
39	  return <ConclusionView row={row} allVersions={allVersions} responses={responses} />;
40	}
