5	export default function CopyButton({ text, label }: { text: string; label: string }) {
6	  const [state, setState] = useState<"idle" | "copied" | "err">("idle");
7	
8	  async function onCopy() {
9	    try {
10	      await navigator.clipboard.writeText(text);
11	      setState("copied");
12	      setTimeout(() => setState("idle"), 1200);
13	    } catch {
14	      setState("err");
15	      setTimeout(() => setState("idle"), 1500);
16	    }
17	  }
18	
19	  return (
20	    <button type="button" className="btn" onClick={() => void onCopy()}>
21	      {state === "copied" ? "Copied" : state === "err" ? "Copy failed" : label}
22	    </button>
23	  );
24	}
