1	"use client";
2	
3	import { useMemo, useState } from "react";
4	
5	import type { PublicConclusion } from "@/lib/types";
6	
7	const KINDS = [
8	  { id: "counter_evidence", label: "Counter-evidence" },
9	  { id: "counter_argument", label: "Counter-argument" },
10	  { id: "clarification", label: "Clarification request" },
11	  { id: "agreement_extension", label: "Agreement with extension" },
12	] as const;
13	
14	export default function RespondForm({ conclusions }: { conclusions: PublicConclusion[] }) {
15	  const portal = process.env.NEXT_PUBLIC_PORTAL_API?.replace(/\/+$/, "") ?? "";
16	  const [publishedId, setPublishedId] = useState(conclusions[0]?.id ?? "");
17	  const [kind, setKind] = useState<string>(KINDS[0].id);
18	  const [body, setBody] = useState("");
19	  const [email, setEmail] = useState("");
20	  const [orcid, setOrcid] = useState("");
21	  const [citationUrl, setCitationUrl] = useState("");
22	  const [pseudonymous, setPseudonymous] = useState(false);
23	  const [msg, setMsg] = useState<string | null>(null);
24	  const [busy, setBusy] = useState(false);
25	
26	  const endpoint = useMemo(() => `${portal}/api/public/responses`, [portal]);
27	
28	  async function submit() {
29	    setMsg(null);
30	    if (!portal) {
31	      setMsg("Set NEXT_PUBLIC_PORTAL_API to your Founder Portal origin (example: http://localhost:3000).");
32	      return;
33	    }
34	    setBusy(true);
35	    try {
36	      const res = await fetch(endpoint, {
37	        method: "POST",
38	        headers: { "Content-Type": "application/json" },
39	        body: JSON.stringify({
40	          publishedConclusionId: publishedId,
41	          kind,
42	          body,
43	          citationUrl,
44	          submitterEmail: email,
45	          orcid,
46	          pseudonymous: pseudonymous,
47	        }),
48	      });
49	      const json = (await res.json().catch(() => ({}))) as { error?: string; ok?: boolean };
50	      if (!res.ok) {
51	        setMsg(json.error || `Submit failed (${res.status})`);
52	        return;
53	      }
54	      setMsg("Submitted. It will be reviewed before it can appear publicly.");
55	      setBody("");
56	    } finally {
57	      setBusy(false);
58	    }
59	  }
60	
61	  return (
62	    <div className="card">
63	      {!portal ? (
64	        <p className="muted" style={{ marginTop: 0 }}>
65	          This static site does not host write APIs. Configure <code>NEXT_PUBLIC_PORTAL_API</code> at build time so the
66	          form can POST to the Founder Portal moderation queue.
67	        </p>
68	      ) : (
69	        <p className="muted" style={{ marginTop: 0 }}>
70	          Posts to <code>{endpoint}</code>
71	        </p>
72	      )}
73	
74	      <label className="muted" style={{ fontSize: "0.9rem", display: "block", marginTop: "0.75rem" }}>
75	        Conclusion revision (published row id)
76	        <select
77	          value={publishedId}
78	          onChange={(e) => setPublishedId(e.target.value)}
79	          style={{ display: "block", width: "100%", marginTop: "0.35rem", padding: "0.5rem" }}
80	        >
81	          {conclusions.map((c) => (
82	            <option key={c.id} value={c.id}>
83	              {c.slug} v{c.version} — {c.publishedAt.slice(0, 10)}
84	            </option>
85	          ))}
86	        </select>
87	      </label>
88	
89	      <label className="muted" style={{ fontSize: "0.9rem", display: "block", marginTop: "0.75rem" }}>
90	        Response type
91	        <select
92	          value={kind}
93	          onChange={(e) => setKind(e.target.value)}
94	          style={{ display: "block", width: "100%", marginTop: "0.35rem", padding: "0.5rem" }}
95	        >
96	          {KINDS.map((k) => (
97	            <option key={k.id} value={k.id}>
98	              {k.label}
99	            </option>
100	          ))}
101	        </select>
102	      </label>
103	
104	      <label className="muted" style={{ fontSize: "0.9rem", display: "block", marginTop: "0.75rem" }}>
105	        Claim (min 20 chars)
106	        <textarea value={body} onChange={(e) => setBody(e.target.value)} rows={7} style={{ display: "block", width: "100%", marginTop: "0.35rem", padding: "0.5rem" }} />
107	      </label>
108	
109	      <label className="muted" style={{ fontSize: "0.9rem", display: "block", marginTop: "0.75rem" }}>
110	        Optional citation URL
111	        <input value={citationUrl} onChange={(e) => setCitationUrl(e.target.value)} style={{ display: "block", width: "100%", marginTop: "0.35rem", padding: "0.5rem" }} />
112	      </label>
113	
114	      <label className="muted" style={{ fontSize: "0.9rem", display: "block", marginTop: "0.75rem" }}>
115	        Email (required; anonymity is not supported)
116	        <input value={email} onChange={(e) => setEmail(e.target.value)} style={{ display: "block", width: "100%", marginTop: "0.35rem", padding: "0.5rem" }} />
117	      </label>
118	
119	      <label className="muted" style={{ fontSize: "0.9rem", display: "block", marginTop: "0.75rem" }}>
120	        ORCID (optional)
121	        <input value={orcid} onChange={(e) => setOrcid(e.target.value)} style={{ display: "block", width: "100%", marginTop: "0.35rem", padding: "0.5rem" }} />
122	      </label>
123	
124	      <label style={{ display: "flex", gap: "0.5rem", alignItems: "center", marginTop: "0.75rem" }} className="muted">
125	        <input type="checkbox" checked={pseudonymous} onChange={(e) => setPseudonymous(e.target.checked)} />
126	        Publish under a pseudonym if approved (still requires verified email; flagged publicly)
127	      </label>
128	
129	      {msg ? <p style={{ marginTop: "0.85rem" }}>{msg}</p> : null}
130	
131	      <div style={{ marginTop: "0.85rem" }}>
132	        <button type="button" className="btn" disabled={busy} onClick={() => void submit()}>
133	          {busy ? "Submitting…" : "Submit for moderation"}
134	        </button>
135	      </div>
136	    </div>
137	  );
138	}
