1	import type { PublicConclusion, PublishedBundle } from "@/lib/types";
2	
3	import raw from "../../content/published.json";
4	
5	export const bundle = raw as PublishedBundle;
6	
7	export function latestConclusions(bundle: PublishedBundle): PublicConclusion[] {
8	  const map = new Map<string, PublicConclusion>();
9	  for (const c of bundle.conclusions) {
10	    const cur = map.get(c.slug);
11	    if (!cur || c.version > cur.version) {
12	      map.set(c.slug, c);
13	    }
14	  }
15	  return [...map.values()].sort((a, b) => a.slug.localeCompare(b.slug));
16	}
17	
18	export function pickConclusion(slug: string, version?: number): PublicConclusion | null {
19	  const rows = bundle.conclusions.filter((c) => c.slug === slug);
20	  if (!rows.length) return null;
21	  if (typeof version === "number") {
22	    return rows.find((c) => c.version === version) ?? null;
23	  }
24	  return rows.reduce((a, b) => (b.version > a.version ? b : a));
25	}
26	
27	export function responsesForPublishedId(publishedId: string): PublishedBundle["responses"] {
28	  return bundle.responses.filter((r) => r.publishedConclusionId === publishedId);
29	}
