21	  const bundle = JSON.parse(fs.readFileSync(pubPath, "utf8"));
22	  const base = (process.env.THESEUS_PUBLIC_SITE_URL || process.env.NEXT_PUBLIC_SITE_URL || "https://theseus.invalid")
23	    .toString()
24	    .replace(/\/+$/, "");
25	  const items = [...bundle.conclusions]
26	    .sort((a, b) => String(b.publishedAt).localeCompare(String(a.publishedAt)))
27	    .map((c) => {
28	      const title = c.payload?.conclusionText || c.slug;
29	      const linkPath = `/c/${encodeURIComponent(c.slug)}/v/${c.version}`;
30	      const abs = `${base}${linkPath}`;
31	      return {
32	        title,
33	        link: abs,
34	        guid: `${c.slug}@v${c.version}`,
35	        pubDate: new Date(c.publishedAt).toUTCString(),
36	        description: c.payload?.evidenceSummary || "",
37	      };
38	    });
39	
40	  const rss = `<?xml version="1.0" encoding="UTF-8"?>
41	<rss version="2.0">
42	  <channel>
43	    <title>Theseus — Published conclusions</title>
44	    <link>${escXml(`${base}/`)}</link>
45	    <description>Chronological updates to published, versioned conclusions.</description>
46	    <language>en-us</language>
47	    ${items
48	      .map(
49	        (it) => `
50	    <item>
51	      <title>${escXml(it.title)}</title>
52	      <link>${escXml(it.link)}</link>
53	      <guid isPermaLink="true">${escXml(it.link)}</guid>
54	      <pubDate>${escXml(it.pubDate)}</pubDate>
55	      <description>${escXml(it.description)}</description>
56	    </item>`,
57	      )
58	      .join("\n")}
59	  </channel>
60	</rss>`;
61	
62	  const atom = `<?xml version="1.0" encoding="UTF-8"?>
63	<feed xmlns="http://www.w3.org/2005/Atom">
64	  <title>Theseus — Published conclusions</title>
65	  <link href="${escXml(`${base}/`)}"/>
66	  <updated>${escXml(new Date(bundle.generatedAt || Date.now()).toISOString())}</updated>
67	  <id>${escXml(`${base}/atom.xml`)}</id>
68	  ${items
69	    .map(
70	      (it) => `
71	  <entry>
72	    <title>${escXml(it.title)}</title>
73	    <link href="${escXml(it.link)}"/>
74	    <id>${escXml(it.guid)}</id>
75	    <updated>${escXml(new Date(it.pubDate).toISOString())}</updated>
76	    <summary>${escXml(it.description)}</summary>
77	  </entry>`,
78	    )
79	    .join("\n")}
80	</feed>`;
81	
82	  fs.writeFileSync(path.join(outDir, "feed.xml"), rss.trim() + "\n", "utf8");
83	  fs.writeFileSync(path.join(outDir, "atom.xml"), atom.trim() + "\n", "utf8");
84	}
85	
86	main();
